#include <iostream>
#include <stdexcept>
using namespace std;

int divide(int a, int b) {
 if (b == 0) {
 throw runtime_error("Division by zero!");
 }
 return a / b;
}

int main() {
 try {
 int result = divide(10, 0);
 cout << "Result: " << result << endl;
 }
 catch (const runtime_error& e) {
 cout << "Exception caught: " << e.what() << endl;
 }
 catch (const exception& e) {
 cout << "Other exception: " << e.what() << endl;
 }
 return 0;
}

#include <iostream>
#include <exception>
#include <string>
using namespace std;

class MyException : public exception {
private:
 string msg;
public:
 MyException(const string& message) : msg(message) {}

 const char* what() const noexcept override {
 return msg.c_str();
 }
};

void process(int age) {
 if (age < 0) {
 throw MyException("Age cannot be negative!");
 }
 if (age > 150) {
 throw MyException("Age is unrealistic!");
 }
 cout << "Valid age: " << age << endl;
}

int main() {
 try {
 process(-5);
 }
 catch (const MyException& e) {
 cout << "Custom exception: " << e.what() << endl;
 }
 return 0;
}

#include <iostream>
#include <stdexcept>
using namespace std;

void level3() {
 throw runtime_error("Original error from level3");
}

void level2() {
 try {
 level3();
 }
 catch (runtime_error& e) {
 cout << "level2 caught: " << e.what() << endl;
 cout << "Rethrowing..." << endl;
 throw; // Rethrows the same exception
 }
}

void level1() {
 try {
 level2();
 }
 catch (runtime_error& e) {
 cout << "level1 caught: " << e.what() << endl;
 }
}

int main() {
 level1();
 return 0;
}

#include <iostream>
#include <stdexcept>
using namespace std;

class Inner {
public:
 Inner(int val) {
 if (val < 0)
 throw runtime_error("Inner: negative value!");
 cout << "Inner created with " << val << endl;
 }
};

class Outer {
 Inner obj;
public:
 Outer(int val) try : obj(val) {
 cout << "Outer constructed successfully" << endl;
 }
 catch (const runtime_error& e) {
 cout << "Caught in Outer: " << e.what() << endl;
 throw; // Must rethrow in function try block for constructors
 }
};

int main() {
 try {
 Outer o(-10);
 }
 catch (const runtime_error& e) {
 cout << "Final catch: " << e.what() << endl;
 }
 return 0;
}

#include <iostream>
#include <stdexcept>
using namespace std;

class Test {
 int id;
public:
 Test(int i) : id(i) {
 cout << "Constructor Test(" << id << ")" << endl;
 }
 ~Test() {
 cout << "Destructor Test(" << id << ")" << endl;
 }
};

void func2() {
 Test t(2);
 cout << "func2 throwing exception..." << endl;
 throw runtime_error("Error in func2");
}

void func1() {
 Test t(1);
 func2();
 cout << "After func2 call" << endl;
}

int main() {
 try {
 func1();
 }
 catch (const exception& e) {
 cout << "Caught: " << e.what() << endl;
 }
 cout << "Program continues..." << endl;
 return 0;
}
